import{_ as t,o as e,c as i,a2 as o}from"./chunks/framework.QoSTM79V.js";const m=JSON.parse('{"title":"Mango App","description":"","frontmatter":{},"headers":[],"relativePath":"mango/mango-app/README.md","filePath":"mango/mango-app/README.md"}'),d={name:"mango/mango-app/README.md"};function s(l,a,n,r,p,c){return e(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="mango-app" tabindex="-1">Mango App <a class="header-anchor" href="#mango-app" aria-label="Permalink to &quot;Mango App&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p><code>mango-app</code> 定义 Mango 后端可部署 Spring Boot 启动入口。它不实现业务能力，只负责把 <code>mango-platform</code>、<code>mango-infra</code> 和业务 starter 装配成可运行进程。</p><p>业务开发者主要在这里决定：本地开发用单体还是微服务、业务 starter 加到哪个 app、运行时配置写在哪里、启动后从哪里确认菜单和接口可用。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>常用入口</th></tr></thead><tbody><tr><td>本地启动完整 Mango 后端</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>选择单体拓扑做业务开发和联调</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>选择微服务拓扑拆分网关、平台服务、业务服务和文件预览服务</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>为新增业务模块提供部署宿主</td><td>Maven 依赖 / HTTP API / Java API</td></tr></tbody></table><h2 id="_3-能力边界" tabindex="-1">3. 能力边界 <a class="header-anchor" href="#_3-能力边界" aria-label="Permalink to &quot;3. 能力边界&quot;">​</a></h2><ul><li>不在 app 模块写业务 Controller、Service、Mapper、Entity 或 migration。</li><li>不在 app 模块放长期领域规则。</li><li>不把微服务调用方依赖本地 <code>core</code> 实现；调用方应使用 <code>starter-remote</code>。</li></ul><h2 id="_4-模块入口" tabindex="-1">4. 模块入口 <a class="header-anchor" href="#_4-模块入口" aria-label="Permalink to &quot;4. 模块入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>默认端口</th><th>职责</th></tr></thead><tbody><tr><td><code>monolith/mango-monolith-app</code></td><td><code>5555</code></td><td>单进程装配完整管理后台能力。</td></tr><tr><td><code>microservice/mango-gateway-app</code></td><td><code>8080</code></td><td>网关、路由、边界鉴权和网关资源同步。</td></tr><tr><td><code>microservice/mango-platform-app</code></td><td><code>8081</code></td><td>平台能力提供方，装配 auth、identity、authorization、system、file、workflow、payment 等本地 starter。</td></tr><tr><td><code>microservice/mango-business-app</code></td><td><code>8082</code></td><td>业务服务宿主，默认依赖平台能力 remote starter。</td></tr><tr><td><code>microservice/mango-file-preview-app</code></td><td><code>8083</code></td><td>文件预览独立部署入口。</td></tr></tbody></table><p>app 只控制进程边界和依赖装配。能力的配置、API、migration、菜单和权限仍看各模块 README。</p><h2 id="_5-接入方式" tabindex="-1">5. 接入方式 <a class="header-anchor" href="#_5-接入方式" aria-label="Permalink to &quot;5. 接入方式&quot;">​</a></h2><p>本地单体启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :mango-monolith-app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spring-boot:run</span></span></code></pre></div><p>本地统一环境脚本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/dev-env.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.development</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/dev-env.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.development</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span></span></code></pre></div><p>微服务分别启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :mango-gateway-app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spring-boot:run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :mango-platform-app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spring-boot:run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :mango-business-app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spring-boot:run</span></span></code></pre></div><p>新增业务 starter：</p><ul><li>单体：加入 <code>mango-monolith-app</code> 或业务自己的单体 app。</li><li>微服务提供方：加入 <code>mango-business-app</code>，使用本地 <code>*-starter</code>。</li><li>微服务调用方：加入调用服务，使用 <code>*-starter-remote</code>。</li></ul><h2 id="_6-配置说明" tabindex="-1">6. 配置说明 <a class="header-anchor" href="#_6-配置说明" aria-label="Permalink to &quot;6. 配置说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置位置</th><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>.env.development</code></td><td><code>MANGO_BACKEND_PORT</code></td><td>单体本地端口。</td></tr><tr><td><code>.env.development</code></td><td><code>MANGO_DB_URL</code>、<code>MANGO_DB_USERNAME</code>、<code>MANGO_DB_PASSWORD</code></td><td>单体本地数据库。</td></tr><tr><td><code>.env.development</code></td><td><code>MANGO_FILE_ROOT</code></td><td>本地文件存储根目录。</td></tr><tr><td><code>.env.development</code></td><td><code>MANGO_CRYPTO_SM4_SECRET_KEY</code></td><td>SM4 密钥，<code>mango workspace init</code> 会写入本地工作区环境。</td></tr><tr><td><code>mango-monolith-app/application.yml</code></td><td><code>mango.persistence.flyway.modules.*.enabled</code></td><td>控制单体各能力模块 migration。</td></tr><tr><td><code>mango-gateway-app/application.yml</code></td><td><code>spring.cloud.gateway.routes</code></td><td>微服务路由到 platform 和 business。</td></tr><tr><td><code>mango-platform-app/application.yml</code></td><td>YAML 中 <code>mango</code> -&gt; <code>flyway</code> -&gt; <code>enabled</code></td><td>当前微服务示例默认关闭 Flyway。</td></tr><tr><td><code>mango-business-app/application.yml</code></td><td>YAML 中 <code>mango</code> -&gt; <code>flyway</code> -&gt; <code>enabled</code></td><td>当前业务服务示例默认关闭 Flyway。</td></tr></tbody></table><p>微服务示例默认使用 H2 内存库并关闭 Flyway，更适合拓扑验证。真实部署需要改为 MySQL、打开目标模块 migration，并补齐注册发现、配置中心、网关路由和安全配置。</p><h3 id="_6-1-nacos-部署配置" tabindex="-1">6.1 Nacos 部署配置 <a class="header-anchor" href="#_6-1-nacos-部署配置" aria-label="Permalink to &quot;6.1 Nacos 部署配置&quot;">​</a></h3><p>微服务和平台能力 app 提供 <code>application-nacos.yml</code>，用于真实注册发现和配置中心部署。Nacos 地址通过环境变量注入：</p><table tabindex="0"><thead><tr><th>环境变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>NACOS_SERVER_ADDR</code></td><td><code>127.0.0.1:8848</code></td><td>Nacos 服务地址。</td></tr><tr><td><code>NACOS_NAMESPACE</code></td><td>空</td><td>Nacos 命名空间。</td></tr><tr><td><code>NACOS_GROUP</code></td><td><code>DEFAULT_GROUP</code></td><td>Nacos 配置分组。</td></tr><tr><td><code>SPRING_PROFILES_ACTIVE</code></td><td>当前 app 默认 profile</td><td>启用 <code>nacos</code> profile 后加载 Nacos 配置。</td></tr></tbody></table><p>本仓库提供 <code>scripts/docker/nacos-compose.yml</code> 作为本地 Nacos 验证物料，应用容器可使用 <code>scripts/docker/mango-app.Dockerfile</code> 构建。部署时仍以具体 app 的 <code>spring.application.name</code> 作为服务名，远程 Resource Registry 和 Feign 动态目标会按模块注册信息解析目标服务。</p><h2 id="_7-api-与扩展" tabindex="-1">7. API 与扩展 <a class="header-anchor" href="#_7-api-与扩展" aria-label="Permalink to &quot;7. API 与扩展&quot;">​</a></h2><p>app 层对外暴露的是 Spring Boot 进程和路由，不暴露复用 Java API。</p><p>常见验证入口：</p><ul><li><code>/actuator/health</code>：健康检查。</li><li><code>/v3/api-docs</code>、<code>/swagger-ui.html</code>：平台 app 和单体的 OpenAPI 文档入口。</li><li><code>/auth/**</code>、<code>/identity/**</code>、<code>/authorization/**</code>、<code>/system/**</code>：平台能力接口。</li><li><code>/biz/**</code>、<code>/business/**</code>：微服务业务路由示例。</li></ul><h2 id="_8-数据与初始化" tabindex="-1">8. 数据与初始化 <a class="header-anchor" href="#_8-数据与初始化" aria-label="Permalink to &quot;8. 数据与初始化&quot;">​</a></h2><p>app 层不拥有业务表。数据库和初始化来自被装配的 starter：</p><ul><li>单体 <code>mango-monolith-app</code> 默认打开 system、authorization、identity、org、captcha、file、template、workflow、job、kv、notice、calendar、numgen、payment、domain 等模块 migration。</li><li>微服务示例 app 当前默认关闭 Flyway，需要真实联调时按服务边界打开对应模块 migration。</li><li>菜单和权限初始化来自 authorization 及各业务模块 migration 或初始化器。</li></ul><p>新增业务模块时，必须确认业务 starter 被 app 引入，否则 migration、Runner、Initializer、Controller 和 Service 都不会进入运行时。</p><h2 id="_9-管理入口" tabindex="-1">9. 管理入口 <a class="header-anchor" href="#_9-管理入口" aria-label="Permalink to &quot;9. 管理入口&quot;">​</a></h2><p>app 层只装配权限能力。菜单、权限和租户数据由 <code>mango-authorization</code>、<code>mango-system</code> 和业务模块初始化。</p><p>拓扑选择对权限的影响：</p><ul><li>单体：本地 starter 直接提供权限、菜单和业务接口。</li><li>微服务平台 app：提供 auth、identity、authorization、system 等平台接口。</li><li>微服务业务 app：通过 remote starter 调用平台能力，并同步自己的业务资源。</li><li>网关：通过 <code>mango-access-gateway-starter</code> 做边界鉴权和路由。</li><li>Resource Registry：单体在本进程消费资源声明；微服务中普通能力 app 远程上报声明，Resource 能力 app 负责注册中心和目标分发。</li></ul><h2 id="_10-快速开始" tabindex="-1">10. 快速开始 <a class="header-anchor" href="#_10-快速开始" aria-label="Permalink to &quot;10. 快速开始&quot;">​</a></h2><ol><li>本地开发优先选择单体，减少服务间调用和配置复杂度。</li><li>业务模块完成 <code>api/core/starter</code> 拆分后，把本地 starter 加入单体或业务服务。</li><li>如果业务服务需要调用平台能力，加入对应 <code>starter-remote</code>。</li><li>在 app 配置中打开业务模块 migration 和必要能力开关。</li><li>启动 app，验证数据库表、菜单、权限、接口和前端页面。</li><li>再根据部署需要拆成网关、平台服务、业务服务和文件预览服务。</li></ol><h2 id="_11-问题排查" tabindex="-1">11. 问题排查 <a class="header-anchor" href="#_11-问题排查" aria-label="Permalink to &quot;11. 问题排查&quot;">​</a></h2><ul><li>业务接口 404：检查 starter 是否加到当前启动 app。</li><li>表没创建：检查 migration 是否随 starter 进入 classpath，Flyway 模块开关是否打开。</li><li>单体能用、微服务不能用：检查调用方是否使用 remote starter、网关路由是否覆盖目标路径。</li><li>菜单初始化了但页面打不开：检查前端页面 key 和菜单 component 是否一致。</li><li>菜单或接口资源未注入：检查部署入口是否装配本地 Resource Registry runtime，微服务能力 app 是否装配 <code>mango-resource-starter-remote</code> 和 <code>mango-resource-sync-starter</code>。</li><li>微服务示例没有真实数据：示例默认 H2 和关闭 Flyway，真实联调要改配置。</li></ul><h2 id="_12-相关文档" tabindex="-1">12. 相关文档 <a class="header-anchor" href="#_12-相关文档" aria-label="Permalink to &quot;12. 相关文档&quot;">​</a></h2><ul><li><a href="./../../mango-pmo/rules/backend/05-module">后端模块规范</a></li><li><a href="./../../mango-pmo/rules/backend/08-test">后端测试规范</a></li><li><a href="./../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li></ul><h2 id="_13-补充资料" tabindex="-1">13. 补充资料 <a class="header-anchor" href="#_13-补充资料" aria-label="Permalink to &quot;13. 补充资料&quot;">​</a></h2><ul><li><a href="https://github.com/HardyDou/mango/blob/main/mango/mango-app/monolith/mango-monolith-app/README.md" target="_blank" rel="noreferrer">单体部署入口</a></li><li><a href="https://github.com/HardyDou/mango/blob/main/mango/mango-app/microservice/README.md" target="_blank" rel="noreferrer">微服务部署入口</a></li><li><a href="https://github.com/HardyDou/mango/blob/main/mango/README.md" target="_blank" rel="noreferrer">Mango 后端根 README</a></li><li><a href="./../../mango-docs/capabilities/README">Mango 能力地图</a></li></ul>`,47)])])}const g=t(d,[["render",s]]);export{m as __pageData,g as default};
